let _gameIpcChannelsCreated = false;

const deleteGameIpcChannels = () => {
  if (!_gameIpcChannelsCreated) {
    log.warn("[ipc] deleteGameIpcChannels skipped: channels not yet created");
    return;
  }
  const blitzCore = getBlitzCore();
  blitzCore.DeleteIpcProducer(BLITZ_IPC_CHANNELS.producers.game);
  blitzCore.DeleteIpcConsumer(BLITZ_IPC_CHANNELS.consumers.game);
  _gameIpcChannelsCreated = false;
  log.warn("[ipc] destroyed game ipc channels.");
};
